package com.finance.tracker.transaction;
import java.math.BigDecimal; import java.time.LocalDate; import java.util.*; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param;
public interface TransactionRepository extends JpaRepository<Transaction,Long> { List<Transaction> findByUserIdOrderByDateDesc(Long userId); Optional<Transaction> findByIdAndUserId(Long id,Long userId); @Query("select coalesce(sum(t.amount),0) from Transaction t where t.user.id=:userId and t.type=:type and t.date between :start and :end") BigDecimal sumByUserAndTypeAndDates(@Param("userId")Long id,@Param("type")TransactionType type,@Param("start")LocalDate start,@Param("end")LocalDate end); @Query("select t.category, coalesce(sum(t.amount),0) from Transaction t where t.user.id=:userId and t.type='EXPENSE' and t.date between :start and :end group by t.category") List<Object[]> expenseByCategory(@Param("userId")Long id,@Param("start")LocalDate start,@Param("end")LocalDate end); }
